import{_ as e,o as l,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"编译器","description":"","frontmatter":{},"headers":[],"relativePath":"ES/工具链/编译器.md","filePath":"ES/工具链/编译器.md","lastUpdated":null}'),s={name:"ES/工具链/编译器.md"};function o(r,a,n,p,c,d){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="编译器" tabindex="-1">编译器 <a class="header-anchor" href="#编译器" aria-label="Permalink to &quot;编译器&quot;">​</a></h1><blockquote><p>想成为记事本编程大师吗？</p></blockquote><h3 id="前言-工具链是什么" tabindex="-1">前言：工具链是什么 <a class="header-anchor" href="#前言-工具链是什么" aria-label="Permalink to &quot;前言：工具链是什么&quot;">​</a></h3><p>编写一个（C语言）程序不过光需要编写源文件，在编写完成之后还需要考虑，如何将文件转化成为计算机可以执行的二进制程序，这个过程需要经历预<strong>处理，编译，汇编，链接</strong>这四个过程才能得到可执行程序，这时就需要一套专门的程序来进行这个过程，而这一套过程所需要的全部程序就是我们这里讲工具链。也许在初学C语言的时候我们没有注意过这些过程都需要哪些程序（那是因为IDE为我们做好了大部分的事情），但是如果想要进一步深入就需要掌握工具链搭建的过程。</p><h3 id="编译过程" tabindex="-1">编译过程 <a class="header-anchor" href="#编译过程" aria-label="Permalink to &quot;编译过程&quot;">​</a></h3><p>C语言的源文件要转换成可执行文件需要经历以下四步：</p><ul><li><p>预处理：将源文件中的宏展开，对条件编译部分进行处理，头文件插入源文件</p></li><li><p>编译：将预处理过的源文件转换成为汇编文件</p></li><li><p>汇编：将汇编文件转换成为由二进制组成的目标文件</p></li><li><p>链接：将所有目标文件和库链接在一起生成可执行程序</p></li></ul><h3 id="编译器概念" tabindex="-1">编译器概念 <a class="header-anchor" href="#编译器概念" aria-label="Permalink to &quot;编译器概念&quot;">​</a></h3><p>在上面所说的编译过程中，大部分任务是由编译器完成的，常见的C语言编译器如下</p><h4 id="pc编译器" tabindex="-1">PC编译器： <a class="header-anchor" href="#pc编译器" aria-label="Permalink to &quot;PC编译器：&quot;">​</a></h4><ul><li><p><strong>GCC：</strong></p><p>GCC(<strong>GNU Compiler Collection</strong>)是一个由GNU组织编写的开源的编译器，在最开始的时候它仅作为C语言编译器（所以它的原名是“GNU C Compiler”），后来逐渐支持多种语言（如C++、Go等）便改为现在的名字。它能支持多种操作系统，如Linux，Windows，Mac等。</p><p>1.在Linux平台上获取GCC仅需要执行下面的命令：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt install build-essential</span></span></code></pre></div><p>2.在Windows平台上使用GCC需要下载MinGW（<em>Minimalist</em> GNU <em>for Windows</em>），然后将所下载文件夹中的<code>/bin</code>目录添加到环境变量当中，就可以在终端中使用gcc命令了。</p><p>下载地址：<a href="https://sourceforge.net/projects/mingw/files/" target="_blank" rel="noreferrer">MinGW - Minimalist GNU for Windows - Browse Files at SourceForge.net</a></p></li><li><p><strong>Clang：</strong></p><p>Clang编译器是由苹果公司开发的，最开始的时候苹果公司也是使用GCC的，据说是苹果想要实现一些C语言的特性但是GNU的人不给苹果添加，于是苹果公司便开始研发自家的编译器，这才有了Clang（<s>Only Apple can do</s>），但是Clang也是开源的。</p><p>Clang编译器的前端是Clang，后端是LLVM（Low Level Virtual Machine）。这里解释一下编译器的前端和后端，可以理解为编译器的两个功能不同的组成部分。</p><ul><li>前端主要负责源码的语法检查，分析源文件生成抽象语法树，中间代码的生成（将抽象语法树转换为中间表示（IR），一种与机器无关的中间代码用于后端优化和目标代码的生成）</li><li>后端主要负责优化，目标文件生成，链接生成可执行程序。</li></ul><p>Clang编译器在Github上开源：<a href="https://github.com/llvm/llvm-project/releases" target="_blank" rel="noreferrer">Clang编译器获取</a></p><p>如何配置： <a href="https://www.cnblogs.com/RioTian/p/17758813.html" target="_blank" rel="noreferrer">在Windows下配置Clang编译器</a></p></li><li><p><strong>MSVC：</strong></p><p>MSVC(Microsoft Visual C++)是微软公司的C/C++开发工具，Windows原生环境不提供类似<strong>gcc</strong>，<strong>Clang</strong>的C/C++语言源程序编译运行工具链，它的编译器都是包含在集成开发环境里的（当然这不是开源的），可以通过下载Microsoft Visual Studio来获取。</p><p>MSVC编译器工具链主要由cl.exe与link.exe构成。其中：</p><ol><li>cl.exe用于控制在 Microsoft C/C++的编译器和链接器</li><li>link.exe 将通用对象文件格式 (COFF) 对象文件和库链接起来，以创建可执行 (.exe) 文件或动态链接库 (DLL)</li><li>用户只需要调用cl.exe，即可完成编译-链接全过程。</li></ol><p>如何使用：<a href="https://learn.microsoft.com/zh-cn/cpp/build/reference/compiler-command-line-syntax?view=msvc-170&amp;viewFallbackFrom=vs-2019" target="_blank" rel="noreferrer">MSVC 编译器命令行语法 | Microsoft Learn</a></p></li></ul><h4 id="嵌入式编译器" tabindex="-1">嵌入式编译器： <a class="header-anchor" href="#嵌入式编译器" aria-label="Permalink to &quot;嵌入式编译器：&quot;">​</a></h4><p>因为编译器是要将源码转换成为机器码的，由于不同的处理器使用不同的指令集，因此相同的源码对于不同的处理器转换成的机器码也不相同。主流的PC计算机都是X86的处理器架构，而嵌入式设备则是arm架构，因此嵌入式开发使用的编译器和和上面介绍的编译器不同，主要由下面三种：</p><ul><li>armcc（AC5）:基于GCC开发的arm平台编译器，并不开源</li><li>armclang (AC6):基于Clang开发的arm平台编译器，并不开源</li><li>Arm GNU 工具链：开源的arm开发工具链，不止支持arm开发。</li></ul><p>官网下载：[用于嵌入式的 AC6编译器](<a href="https://developer.arm.com/Tools" target="_blank" rel="noreferrer">https://developer.arm.com/Tools</a> and Software/Arm Compiler for Embedded) <a href="https://developer.arm.com/downloads/-/gnu-rm" target="_blank" rel="noreferrer">GNU Arm 嵌入式工具链下载</a></p><h3 id="gcc的使用" tabindex="-1">GCC的使用 <a class="header-anchor" href="#gcc的使用" aria-label="Permalink to &quot;GCC的使用&quot;">​</a></h3><h4 id="编译过程-1" tabindex="-1">编译过程： <a class="header-anchor" href="#编译过程-1" aria-label="Permalink to &quot;编译过程：&quot;">​</a></h4><p>预处理：</p><p>执行下面的命令编译器就只会进行预处理，然后将处理后的文件输出到<code>test.i</code>这个文件中（选项大小写敏感）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ gcc -E -o test.i test.c #-C选项可以阻止删除注释，</span></span></code></pre></div><p>编译：</p><p>执行下面的命令编译器执行完编译部分就会停止，并将翻译得到的汇编结果存放在<code>.s</code>文件之中。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ gcc -S test.c #加上-fverbose-asm选项可以将C语言中变量名作为注释</span></span></code></pre></div><p>汇编</p><p>由于不同的机器机构有着不同的汇编语言，因此GCC通过调用宿主系统的汇编器来生成对象文件（object file，包含描述所有外部链接的符号表和源文件汇编生成的二进制机器码），执行下面命令生成对象文件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ gcc -c test.c #小写的c</span></span></code></pre></div><p>链接</p><p>将对象文件中所需要的外部链接与对象文件链接成可执行文件文件，如下例中，将两个对象文件链接</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ gcc -o circle circle.o circulararea.o —lncurses</span></span></code></pre></div><p>共享链接库是一个特殊的对象文件，在运行时才被链接到程序，这样能使可执行文件更小，同时便于共享模块更新。通过下面的方法创建共享链接库：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ gcc -shared -o libcirculararea.so circulararea.o</span></span></code></pre></div><h4 id="常用的选项" tabindex="-1">常用的选项： <a class="header-anchor" href="#常用的选项" aria-label="Permalink to &quot;常用的选项：&quot;">​</a></h4><ul><li>-v 显示版本信息</li><li>-w 取消所有警告</li><li>-Wall 对所有问题输出警告</li><li>-std=&lt;语言标准 &gt; 支持的语言的标准<code>-std=c11</code>表示支持c11标准</li><li>-c 只预处理，编译，汇编，不链接</li><li>-C 预处理保留注释</li><li>-E 只执行预处理，不结合-o使用会将结果输出到stdour</li><li>-s 删除可执行文件的符号表</li><li>-S 只执行预处理和编译</li><li>-save-tems 保留中间输出文件</li><li>-shared 创建共享对象文件</li><li>-ename 指定程序从<code>name</code>处开始执行</li><li>-g 生成GDB调试所需要的符号表</li></ul><h4 id="文件类型" tabindex="-1">文件类型： <a class="header-anchor" href="#文件类型" aria-label="Permalink to &quot;文件类型：&quot;">​</a></h4><ul><li>.c C语言源文件</li><li>.i C程序预处理后的文件，可以被编译。</li><li>.h C程序头文件。</li><li>.s 汇编文件</li><li>.S 有C语言的汇编文件，进行汇编前需要预处理</li><li>.o 对象文件</li><li>.exe 可执行文件</li></ul><h4 id="优化等级" tabindex="-1">优化等级： <a class="header-anchor" href="#优化等级" aria-label="Permalink to &quot;优化等级：&quot;">​</a></h4><ul><li><p>-O0:</p><p>关闭所有优化选项</p></li><li><p>-O/-O1:</p><p>让可执行文件更小、执行得更快，但是不会因此增加过多的编译时间。所采用的技术包括：合并一致的常量、优化基本循环，以及在连续函数调用后对栈操作分组。</p></li><li><p>-O2:</p><p>应用几乎所有支持的优化技术，只要这些优化技术不涉及程序大小与执行速度之间的相互取舍。使用该选项通常情况下会增加编译时间。</p></li><li><p>-O3:</p><p>生成 inline 函数，并且让变量在 CPU 寄存器中更加灵活地分配空间。同时也包括了2 所有的优化技术。</p></li><li><p>-Os：</p><p>优化程序大小。这个选项类似-O2 ，但没有包括任何可能导致代码大小增加的优化技术。而且，禁用块重新排序、函数对齐，以及其他以 2 为指数字节边界目的地的跳转操作。如果希望获得更小的可执行文件，可以使用 GCC 选项-s来编译，该选项指示链接器在所有必须的函数和对象被链接后，把所有符号表从执行的输出文件中删除。</p></li></ul>',37)])])}const g=e(s,[["render",o]]);export{u as __pageData,g as default};
